#include <cstdlib>
#include <iostream>
#include <string>
#include <cstring>
#include <cmath>
#include <cstdio>

#include "translated_0.cu"

#define MAX_THREADS_PER_BLOCK 256

struct Node {
    int starting;
    int no_of_edges;
};

int work_group_size = 512;

void run_bfs_cpu(int no_of_nodes, Node *h_graph_nodes, int edge_list_size,
                 int *h_graph_edges, char *h_graph_mask, char *h_updating_graph_mask,
                 char *h_graph_visited, int *h_cost_ref)
{
    char stop;
    int k = 0;
    do {
        stop = false;
        for(int tid = 0; tid < no_of_nodes; tid++ ) {
            if (true == h_graph_mask[tid]) {
                h_graph_mask[tid] = false;
                int start = h_graph_nodes[tid].starting;
                int end = start + h_graph_nodes[tid].no_of_edges;
                for(int i = start; i < end; i++) {
                    int id = h_graph_edges[i];
                    if(!h_graph_visited[id]) {
                        h_cost_ref[id] = h_cost_ref[tid] + 1;
                        h_updating_graph_mask[id] = true;
                    }
                }
            }
        }

        for(int tid = 0; tid < no_of_nodes; tid++ ) {
            if (true == h_updating_graph_mask[tid]) {
                h_graph_mask[tid] = true;
                h_graph_visited[tid] = true;
                stop = true;
                h_updating_graph_mask[tid] = false;
            }
        }
        k++;
    } while(stop);
}

void run_bfs_gpu(int no_of_nodes, Node *h_graph_nodes, int edge_list_size,
                 int *h_graph_edges, char *h_graph_mask, char *h_updating_graph_mask,
                 char *h_graph_visited, int *h_cost)
{
    char h_over;
    Node *d_graph_nodes = nullptr;
    int *d_graph_edges = nullptr;
    char *d_graph_mask = nullptr;
    char *d_updating_graph_mask = nullptr;
    char *d_graph_visited = nullptr;
    int *d_cost = nullptr;
    char *d_over = nullptr;

    cudaError_t err;

    err = cudaMalloc((void**)&d_graph_nodes, no_of_nodes * sizeof(Node));
    if (err != cudaSuccess) throw std::string("cudaMalloc d_graph_nodes failed");

    err = cudaMalloc((void**)&d_graph_edges, edge_list_size * sizeof(int));
    if (err != cudaSuccess) throw std::string("cudaMalloc d_graph_edges failed");

    err = cudaMalloc((void**)&d_graph_mask, no_of_nodes * sizeof(char));
    if (err != cudaSuccess) throw std::string("cudaMalloc d_graph_mask failed");

    err = cudaMalloc((void**)&d_updating_graph_mask, no_of_nodes * sizeof(char));
    if (err != cudaSuccess) throw std::string("cudaMalloc d_updating_graph_mask failed");

    err = cudaMalloc((void**)&d_graph_visited, no_of_nodes * sizeof(char));
    if (err != cudaSuccess) throw std::string("cudaMalloc d_graph_visited failed");

    err = cudaMalloc((void**)&d_cost, no_of_nodes * sizeof(int));
    if (err != cudaSuccess) throw std::string("cudaMalloc d_cost failed");

    err = cudaMalloc((void**)&d_over, sizeof(char));
    if (err != cudaSuccess) throw std::string("cudaMalloc d_over failed");

    err = cudaMemcpy(d_graph_nodes, h_graph_nodes, no_of_nodes * sizeof(Node), cudaMemcpyHostToDevice);
    if (err != cudaSuccess) throw std::string("cudaMemcpy d_graph_nodes failed");

    err = cudaMemcpy(d_graph_edges, h_graph_edges, edge_list_size * sizeof(int), cudaMemcpyHostToDevice);
    if (err != cudaSuccess) throw std::string("cudaMemcpy d_graph_edges failed");

    err = cudaMemcpy(d_graph_mask, h_graph_mask, no_of_nodes * sizeof(char), cudaMemcpyHostToDevice);
    if (err != cudaSuccess) throw std::string("cudaMemcpy d_graph_mask failed");

    err = cudaMemcpy(d_updating_graph_mask, h_updating_graph_mask, no_of_nodes * sizeof(char), cudaMemcpyHostToDevice);
    if (err != cudaSuccess) throw std::string("cudaMemcpy d_updating_graph_mask failed");

    err = cudaMemcpy(d_graph_visited, h_graph_visited, no_of_nodes * sizeof(char), cudaMemcpyHostToDevice);
    if (err != cudaSuccess) throw std::string("cudaMemcpy d_graph_visited failed");

    err = cudaMemcpy(d_cost, h_cost, no_of_nodes * sizeof(int), cudaMemcpyHostToDevice);
    if (err != cudaSuccess) throw std::string("cudaMemcpy d_cost failed");

    int num_blocks = (no_of_nodes + work_group_size - 1) / work_group_size;

    do {
        h_over = false;
        err = cudaMemcpy(d_over, &h_over, sizeof(char), cudaMemcpyHostToDevice);
        if (err != cudaSuccess) throw std::string("cudaMemcpy d_over failed");

        BFS_1<<<num_blocks, work_group_size>>>(d_graph_nodes, d_graph_edges, d_graph_mask, d_updating_graph_mask, d_graph_visited, d_cost, no_of_nodes);
        cudaDeviceSynchronize();

        BFS_2<<<num_blocks, work_group_size>>>(d_graph_mask, d_updating_graph_mask, d_graph_visited, d_over, no_of_nodes);
        cudaDeviceSynchronize();

        err = cudaMemcpy(&h_over, d_over, sizeof(char), cudaMemcpyDeviceToHost);
        if (err != cudaSuccess) throw std::string("cudaMemcpy d_over to host failed");
    } while(h_over);

    err = cudaMemcpy(h_cost, d_cost, no_of_nodes * sizeof(int), cudaMemcpyDeviceToHost);
    if (err != cudaSuccess) throw std::string("cudaMemcpy h_cost failed");

    cudaFree(d_graph_nodes);
    cudaFree(d_graph_edges);
    cudaFree(d_graph_mask);
    cudaFree(d_updating_graph_mask);
    cudaFree(d_graph_visited);
    cudaFree(d_cost);
    cudaFree(d_over);
}

void Usage(int argc, char**argv)
{
    fprintf(stderr,"Usage: %s <input_file> [-p platform] [-d device] [-t gpu(0)/cpu(1)]\n", argv[0]);
}

int main(int argc, char * argv[])
{
    int no_of_nodes;
    int edge_list_size;
    FILE *fp;
    Node* h_graph_nodes = nullptr;
    char *h_graph_mask = nullptr, *h_updating_graph_mask = nullptr, *h_graph_visited = nullptr;
    try {
        char *input_f;
        if(2 > argc) {
            Usage(argc, argv);
            exit(0);
        }

        input_f = argv[1];
        printf("Reading File\n");

        fp = fopen(input_f,"r");
        if(!fp) {
            printf("Error Reading graph file\n");
            return 0;
        }

        int source = 0;

        fscanf(fp,"%d",&no_of_nodes);

        int num_of_blocks = 1;
        int num_of_threads_per_block = no_of_nodes;

        if(MAX_THREADS_PER_BLOCK < no_of_nodes) {
            num_of_blocks = (int)ceil(no_of_nodes/(double)MAX_THREADS_PER_BLOCK);
            num_of_threads_per_block = MAX_THREADS_PER_BLOCK;
        }
        work_group_size = num_of_threads_per_block;

        h_graph_nodes = (Node*) malloc(sizeof(Node)*no_of_nodes);
        h_graph_mask = (char*) malloc(sizeof(char)*no_of_nodes);
        h_updating_graph_mask = (char*) malloc(sizeof(char)*no_of_nodes);
        h_graph_visited = (char*) malloc(sizeof(char)*no_of_nodes);

        int start, edgeno;

        for(int i = 0; i < no_of_nodes; i++) {
            fscanf(fp,"%d %d",&start,&edgeno);
            h_graph_nodes[i].starting = start;
            h_graph_nodes[i].no_of_edges = edgeno;
            h_graph_mask[i] = false;
            h_updating_graph_mask[i] = false;
            h_graph_visited[i] = false;
        }

        fscanf(fp,"%d",&source);
        source = 0;

        h_graph_mask[source] = true;
        h_graph_visited[source] = true;
        fscanf(fp,"%d",&edge_list_size);
        int id,cost;
        int* h_graph_edges = (int*) malloc(sizeof(int)*edge_list_size);
        for(int i=0; i < edge_list_size; i++) {
            fscanf(fp,"%d",&id);
            fscanf(fp,"%d",&cost);
            h_graph_edges[i] = id;
        }

        if(fp)
            fclose(fp);

        int	*h_cost = (int*) malloc(sizeof(int)*no_of_nodes);
        int *h_cost_ref = (int*)malloc(sizeof(int)*no_of_nodes);
        for(int i=0; i < no_of_nodes; i++) {
            h_cost[i] = -1;
            h_cost_ref[i] = -1;
        }
        h_cost[source] = 0;
        h_cost_ref[source] = 0;

        run_bfs_gpu(no_of_nodes, h_graph_nodes, edge_list_size, h_graph_edges, h_graph_mask, h_updating_graph_mask, h_graph_visited, h_cost);

        for(int i = 0; i < no_of_nodes; i++) {
            h_graph_mask[i] = false;
            h_updating_graph_mask[i] = false;
            h_graph_visited[i] = false;
        }

        source = 0;
        h_graph_mask[source] = true;
        h_graph_visited[source] = true;
        run_bfs_cpu(no_of_nodes, h_graph_nodes, edge_list_size, h_graph_edges, h_graph_mask, h_updating_graph_mask, h_graph_visited, h_cost_ref);

        // compare_results<int> is defined in util.h, inline here:
        bool passed = true;
        for (int i = 0; i < no_of_nodes; i++) {
            if (h_cost_ref[i] != h_cost[i]) {
                passed = false;
                break;
            }
        }
        if (passed) {
            std::cout << "--cambine:passed:-)" << std::endl;
        } else {
            std::cout << "--cambine: failed:-(" << std::endl;
        }

        free(h_graph_nodes);
        free(h_graph_mask);
        free(h_updating_graph_mask);
        free(h_graph_visited);
        free(h_graph_edges);
        free(h_cost);
        free(h_cost_ref);

    } catch(std::string msg) {
        std::cout<<"--cambine: exception in main ->"<<msg<<std::endl;

        free(h_graph_nodes);
        free(h_graph_mask);
        free(h_updating_graph_mask);
        free(h_graph_visited);
    }

    return 0;
}

